class Solution:
    def theMaximumAchievableX(self, num, t):
        best = None
        for x in range(num - 2 * t - 5, num + 2 * t + 6):
            diff = x - num
            if diff % 2 == 0 and abs(diff) <= 2 * t:
                if best is None or x > best:
                    best = x
        return best

